import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"충돌 보고서","description":"충돌 보고서가 어떤 역할을 가지고, 어떻게 읽는지 알아보세요.","frontmatter":{"title":"충돌 보고서","description":"충돌 보고서가 어떤 역할을 가지고, 어떻게 읽는지 알아보세요.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"ko_kr/1.20.4/players/troubleshooting/crash-reports.md","filePath":"versions/1.20.4/translated/ko_kr/players/troubleshooting/crash-reports.md","lastUpdated":1766341111000}`);var a={name:`ko_kr/1.20.4/players/troubleshooting/crash-reports.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">충돌 보고서 <a class="header-anchor" href="#h1" aria-label="Permalink to “충돌 보고서”">​</a></h1><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>충돌의 원인을 찾는 데 어려움이 있으시다면, <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord (영어)</a> 의 <code>#player-support</code> 또는 <code>#server-admin-support</code> 채널에 도움을 요청할 수 있습니다.</p></div><p>충돌 보고서는 게임 또는 서버의 문제를 해결하기 위해 굉장히 중요한 부분 중 하나입니다. 이러한 충돌 보고서는 충돌에 관련된 많은 정보를 포함하고 있으며, 충돌의 원인을 찾는 데 도움이 됩니다.</p><h2 id="충돌-보고서-찾기" tabindex="-1">충돌 보고서 찾기 <a class="header-anchor" href="#충돌-보고서-찾기" aria-label="Permalink to “충돌 보고서 찾기”">​</a></h2><p>충돌 보고서는 게임 디렉토리의 <code>crash-reports</code> 폴더에 저장됩니다. 서버의 경우, 서버 디렉토리의 <code>crash-reports</code> 폴더에 저장됩니다.</p><p>서드 파티 런처의 경우, 충돌 보고서를 찾으려면 해당 런처의 문서를 참고해야 할 수 있습니다.</p><p>충돌 보고서는 다음과 같은 위치에서 찾을 수 있습니다.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-23" id="tab-24" checked><label data-title="Windows" for="tab-24">Windows</label><input type="radio" name="group-23" id="tab-25"><label data-title="macOS" for="tab-25">macOS</label><input type="radio" name="group-23" id="tab-26"><label data-title="Linux" for="tab-26">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/crash-reports</span></span></code></pre></div></div></div><h2 id="충돌-보고서-읽기" tabindex="-1">충돌 보고서 읽기 <a class="header-anchor" href="#충돌-보고서-읽기" aria-label="Permalink to “충돌 보고서 읽기”">​</a></h2><p>충돌 보고서는 매우 길고, 읽기 매우 어려울 수 있습니다. 하지만, 충돌에 관련된 많은 정보를 포함하고 있고, 충돌의 원인을 찾는데 유용합니다.</p><p>이 가이드에선, <a href="https://github.com/FabricMC/fabric-docs/blob/main/public/assets/players/crash-report-example.log" target="_blank" rel="noreferrer">이 충돌 보고서를 예시로</a> 보고서를 읽어 볼 것입니다.</p><h3 id="충돌-보고서의-목차" tabindex="-1">충돌 보고서의 목차 <a class="header-anchor" href="#충돌-보고서의-목차" aria-label="Permalink to “충돌 보고서의 목차”">​</a></h3><p>충돌 보고서는 여러 목차로 이루어져 있으며, 각 목차는 다음 제목을 가집니다.</p><ul><li><code>---- Minecraft Crash Report ----</code>, 보고서 요약본. 이는 충돌을 일으킨 주요 오류, 발생한 시간, 그리고 관련 스택트레이스로 이루어집니다. 대부분의 경우에서 스택트레이스에 충돌을 일으킨 모드의 리퍼런스가 포함되므로 보고서의 가장 중요한 부분이라고 할 수 있습니다.</li><li><code>-- Last Reload --</code>, 충돌이 리소스 다시 로드 (<kbd>F3</kbd>+<kbd>T</kbd>) 도중 발생하지 않았다면 대부분 불필요합니다. 다시 로드가 진행된 시간, 다시 로드 중 발생한 오류의 관련 스택 트레이스 등을 포함합니다. 이러한 오류는 대부분 리소스 팩에서 발생하며, 게임에 문제를 일으키지 않는 한 신경 쓸 필요는 없습니다.</li><li><code>-- System Details --</code>, 시스템에 대한 정보. 운영체제, Java 버전, 게임에 할당된 메모리의 양 등이 기록됩니다. 게임에 적당한 양의 메모리가 할당되었는지, 올바른 Java 버전을 사용했는지 등을 확인할 때 유용합니다. <ul><li>Fabric의 경우, 여기에 설치된 모드가 기록되는 <code>Fabric Mods:</code> 가 추가됩니다. 모드 간 충돌을 파악할 때 유용합니다.</li></ul></li></ul><h3 id="충돌-보고서-분해하기" tabindex="-1">충돌 보고서 분해하기 <a class="header-anchor" href="#충돌-보고서-분해하기" aria-label="Permalink to “충돌 보고서 분해하기”">​</a></h3><p>이제 충돌 보고서의 목차를 알았으니, 충돌 보고서를 분해해서 충돌의 원인이 무엇인지 파악할 수 있게 되었습니다.</p><p>아래에 링크된 예시를 통해, 충돌 보고서를 분석하고 충돌을 일으킨 원인과 모드를 찾아봅시다.</p><p>이 예시에서는 <code>---- Minecraft Crash Report ----</code> 의 스택트레이스에 충돌을 일으킨 주요 오류가 기록되어 있으므로, 가장 중요한 부분이라 할 수 있습니다. 예시에서 발생한 오류는 <code>java.lang.NullPointerException: Cannot invoke &quot;net.minecraft.class_2248.method_9539()&quot; because &quot;net.minecraft.class_2248.field_10540&quot; is null</code> 입니다.</p><p>스택트레이스에 언급된 모드의 개수에 따라, 정확히 지목하기 어려울 수 있지만, 가장 먼저 해야 할 일은 충돌을 일으킨 모드를 찾는 것입니다.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>at snownee.snow.block.ShapeCaches.get(ShapeCaches.java:51)</span></span>
<span class="line"><span>at snownee.snow.block.SnowWallBlock.method_9549(SnowWallBlock.java:26) // [!code focus]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>at me.jellysquid.mods.sodium.client.render.chunk.compile.pipeline.BlockOcclusionCache.shouldDrawSide(BlockOcclusionCache.java:52)</span></span>
<span class="line"><span>at link.infra.indium.renderer.render.TerrainBlockRenderInfo.shouldDrawFaceInner(TerrainBlockRenderInfo.java:31)</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>이 예시에서는, 스택트레이스에서 처음으로 언급 된 <code>snownee</code> 가 충돌을 일으킨 모드입니다.</p><p>하지만, 여러 모드가 비슷한 비율로 언급되었다면, 모드 간 호환성 문제일 수 있으며, 충돌을 일으킨 모드의 코드는 문제가 없을 가능성도 있습니다. 이런 경우에는, 모드 개발자에서 충돌을 신고하고, 개발자가 충돌을 파악하도록 하는 것이 최고의 선택입니다.</p><h2 id="mixin-충돌" tabindex="-1">Mixin 충돌 <a class="header-anchor" href="#mixin-충돌" aria-label="Permalink to “Mixin 충돌”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Mixin은 게임의 소스 코드를 수정하지 않고 게임을 수정하는 방법 중 하나입니다. 이는 여러 모드에서 사용되고, 개발자에게 가장 강력한 도구가 됩니다.</p></div><p>Mixin이 충돌하면, 스택 트레이스에는 충돌이 발생한 Mixin과, Mixin을 수정하려고 시도한 모드가 기록됩니다.</p><p>메소드 Mixin은 스택트레이스에 <code>mod-id$handlerName</code> 로 기록되는데, <code>mod-id</code>는 모드의 아이디, <code>handlerName</code>은 Mixin 처리기의 이름입니다.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>... net.minecraft.class_2248.method_3821$$$mod-id$handlerName() ... // [!code focus]</span></span></code></pre></div><p>이 정보를 통해 충돌을 일으킨 모드를 찾고, 모드 개발자에게 충돌을 신고할 수 있게 됩니다.</p><h2 id="충돌-보고서로-할-수-있는-것" tabindex="-1">충돌 보고서로 할 수 있는 것 <a class="header-anchor" href="#충돌-보고서로-할-수-있는-것" aria-label="Permalink to “충돌 보고서로 할 수 있는 것”">​</a></h2><p>충돌 보고서로 할 수 있는 최고의 행동은 보고서를 기록(Paste) 사이트에 업로드 하고, 이슈 트래커 또는 커뮤니티에 게시하여 모드 개발자에게 공유하는 것입니다.</p><p>이는 모드 개발자가 충돌을 재현하는 등 분석하고, 충돌을 해결할 수 있게 합니다.</p><p>일반적으로 충돌 보고서에 사용되는 기록 사이트는 다음과 같습니다.</p><ul><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,33)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};